request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?forwardTask ?forwardName ?emailTask ?emailName
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0ba102e82f484407a4dbcb9bcafdd920" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?forwardTask a bboExt:ChoreographyTask ;
               tai:belongsTo ?choreo ;
               bbo:name ?forwardName .
  FILTER(CONTAINS(LCASE(STR(?forwardName)), LCASE("Forward Application")))

  ?emailTask a bboExt:ChoreographyTask ;
              tai:belongsTo ?choreo ;
              bbo:name ?emailName .
  FILTER(CONTAINS(LCASE(STR(?emailName)), LCASE("Email Results of Academic Review")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?norm ?orig ?created ?name
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?norm .
  OPTIONAL { ?model tai:originalId ?orig . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model bbo:name ?name . }
  FILTER(?norm = "0ba102e82f484407a4dbcb9bcafdd920")
}
LIMIT 25
